module divider (
    input [1:0] numerator,
    input [1:0] obf_denominator,
    output reg [1:0] quotient,
    output reg [1:0] remainder
);
    always @(*) begin
        if (obf_denominator == 2'b00) begin
            quotient = 2'b00;
            remainder = 2'b00;
        end else begin
            quotient = numerator / obf_denominator;
            remainder = numerator % obf_denominator;
        end
    end
endmodule
